```cpp
template <typename F, typename G>
class ComposedFunctor {
    F f;
    G g;
public:
    ComposedFunctor(F f_, G g_) : f(f_), g(g_) {}

    template <typename T>
    auto operator()(T&& x) const -> decltype(f(g(std::forward<T>(x)))) {
        return f(g(std::forward<T>(x)));  // f(g(x))
    }
};
