        vector<shared_ptr<CollisionObserver>> active;
        {
            lock_guard lock(mtx);
            for (auto& wp : observers) {
                if (auto obs = wp.lock()) active.push_back(obs);
            }
        }

        for (auto& obs : active) {
            obs->onCollisionDetected(event);
        }
    }
};

