                          [](const std::weak_ptr<Observer>& wp) {
                              return wp.expired();
                          }),
            observers.end()
        );

        // Notify alive observers
        for (auto& wp : observers) {
            if (auto observer = wp.lock()) {  // Convert to shared_ptr
                observer->update(currentTemperature);
