    if (data.isLarge()) {  // ❌ Business logic in Context
        strategy = &parallelStrategy;
    } else if (data.isCritical()) {
        strategy = &accurateStrategy;
    } else {
        strategy = &fastStrategy;
    }
    strategy->process(data);
}
```
